package org.apache.commons.csv;
import static org.apache.commons.csv.Token.Type.TOKEN;
import java.io.Closeable;
import java.io.FileReader;
import java.io.Reader;
import java.io.StringReader;
import java.util.ArrayList;
import java.util.Collection;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void testParse_withValidUrlCharsetAndFormat() throws Exception {
        // Arrange
        URL mockUrl = mock(URL.class);
        InputStream mockInputStream = mock(InputStream.class);
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        when(mockUrl.openStream()).thenReturn(mockInputStream);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            // Act
            CSVParser parser = CSVParser.parse(mockUrl, charset, format);

            // Assert
            assertNotNull(parser);
            assertEquals(format, parser.format);
            assertFalse(parser.isClosed());
            assertionsMockedStatic.verify(() -> Assertions.notNull(mockUrl, "url"));
            assertionsMockedStatic.verify(() -> Assertions.notNull(charset, "charset"));
            assertionsMockedStatic.verify(() -> Assertions.notNull(format, "format"));
        }
    }

    @Test
    void testParse_withNullUrl_throwsException() {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(null, "url"))
                .thenThrow(new NullPointerException("url"));

            NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(null, charset, format);
            });
            assertEquals("url", thrown.getMessage());
        }
    }

    @Test
    void testParse_withNullCharset_throwsException() throws Exception {
        URL mockUrl = mock(URL.class);
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(mockUrl, "url")).thenReturn(null);
            assertionsMockedStatic.when(() -> Assertions.notNull(null, "charset"))
                .thenThrow(new NullPointerException("charset"));

            NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(mockUrl, null, format);
            });
            assertEquals("charset", thrown.getMessage());
        }
    }

    @Test
    void testParse_withNullFormat_throwsException() throws Exception {
        URL mockUrl = mock(URL.class);
        Charset charset = Charset.forName("UTF-8");

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(mockUrl, "url")).thenReturn(null);
            assertionsMockedStatic.when(() -> Assertions.notNull(charset, "charset")).thenReturn(null);
            assertionsMockedStatic.when(() -> Assertions.notNull(null, "format"))
                .thenThrow(new NullPointerException("format"));

            NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(mockUrl, charset, null);
            });
            assertEquals("format", thrown.getMessage());
        }
    }

    @Test
    void testParse_withUrlOpenStreamThrowsIOException() throws Exception {
        URL mockUrl = mock(URL.class);
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        when(mockUrl.openStream()).thenThrow(new IOException("Stream error"));

        IOException thrown = assertThrows(IOException.class, () -> {
            CSVParser.parse(mockUrl, charset, format);
        });
        assertEquals("Stream error", thrown.getMessage());
    }
}
